const items = $input.all();
const results = [];
for (const item of items) {
  const cliente = item.json;
  const causas = Array.isArray(cliente.causas_insatisfacao)
    ? cliente.causas_insatisfacao.join(', ')
    : JSON.stringify(cliente.causas_insatisfacao || []);
  const prompt = `Cliente com alto risco de churn. Gere uma estratégia de retenção personalizada e retorne um JSON com:\n- estrategia: texto descritivo da estratégia de retenção (máximo 500 caracteres)\n- oferta_personalizada: descrição da oferta ou benefício a ser apresentado\n- prioridade_score: número de 1 a 100 (100 = máxima prioridade)\n- prazo_acao: string no formato ISO 8601 da data limite para ação (máximo 7 dias a partir de hoje)\n\nDados do cliente:\n- Canal: ${cliente.canal}\n- Tom emocional: ${cliente.tom_emocional}\n- NPS comportamental: ${cliente.nps_comportamental}\n- Causas de insatisfação: ${causas}\n- Momento crítico: ${cliente.momento_critico}\n\nRetorne APENAS o JSON, sem explicações.`;
  results.push({
    json: {
      ...cliente,
      prompt
    }
  });
}
return results;

const response = $input.first().json;
const content = response.content?.[0]?.text || '{}';
let parsed;
try { parsed = JSON.parse(content); } catch(e) { parsed = {erro: 'parse_failed', raw: content.substring(0,200)}; }
return [{json: {...$input.first().json, resultado: parsed}}];
